content:
{
  "sentences": [
    {
      "text": "我想預約看診，請問明天上午有空嗎？",
      "pinyin": "Wǒ xiǎng yùyuē kànzhěn, qǐngwèn míngtiān shàngwǔ yǒu kòng ma?",
      "pinyin_numeric": "wo3 xiang3 yu4yue1 kan4zhen3, qing3wen4 ming2tian1 shang4wu3 you3 kong4 ma0",
      "translation_en": "I want to make an appointment to see a doctor. Do you have availability tomorrow morning?",
      "translation_ko": "진료 예약을 하고 싶은데요, 내일 오전에 시간이 있나요?"
    },
    {
      "text": "我想訂位，請問今天晚上有兩個人的座位嗎？",
      "pinyin": "Wǒ xiǎng dìngwèi, qǐngwèn jīntiān wǎnshang yǒu liǎng gè rén de zuòwèi ma?",
      "pinyin_numeric": "wo3 xiang3 ding4wei4, qing3wen4 jin1tian1 wan3shang5 you3 liang3 ge4 ren2 de0 zuo4wei4 ma0",
      "translation_en": "I want to make a reservation. Do you have a table for two tonight?",
      "translation_ko": "예약을 하고 싶은데요, 오늘 저녁에 두 명 자리가 있나요?"
    },
    {
      "text": "我想外帶一份牛肉麵，請問要等多久？",
      "pinyin": "Wǒ xiǎng wàidài yī fèn niúròumiàn, qǐngwèn yào děng duōjiǔ?",
      "pinyin_numeric": "wo3 xiang3 wai4dai4 yi1 fen4 niu2rou4mian4, qing3wen4 yao4 deng3 duo1jiu3",
      "translation_en": "I want to order one beef noodle soup for takeout. How long will it take?",
      "translation_ko": "소고기 국수 하나를 포장하고 싶은데요, 얼마나 기다려야 하나요?"
    },
    {
      "text": "我想請問你們的營業時間，請問今天有休息嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen de yíngyè shíjiān, qǐngwèn jīntiān yǒu xiūxi ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men5 de0 ying2ye4 shi2jian1, qing3wen4 jin1tian1 you3 xiu1xi5 ma0",
      "translation_en": "I want to ask about your business hours. Are you closed today?",
      "translation_ko": "영업 시간을 여쭤보고 싶은데요, 오늘 쉬시나요?"
    },
    {
      "text": "我想找王小姐，請問她在嗎？",
      "pinyin": "Wǒ xiǎng zhǎo Wáng xiǎojiě, qǐngwèn tā zài ma?",
      "pinyin_numeric": "wo3 xiang3 zhao3 Wang2 xiao3jie3, qing3wen4 ta1 zai4 ma0",
      "translation_en": "I want to speak with Miss Wang. Is she available?",
      "translation_ko": "왕 씨를 찾고 있는데요, 계신가요?"
    },
    {
      "text": "我想訂外送，請問你們有送到這個地址嗎？",
      "pinyin": "Wǒ xiǎng dìng wàisòng, qǐngwèn nǐmen yǒu sòng dào zhège dìzhǐ ma?",
      "pinyin_numeric": "wo3 xiang3 ding4 wai4song4, qing3wen4 ni3men5 you3 song4 dao4 zhe4ge4 di4zhi3 ma0",
      "translation_en": "I want to order delivery. Do you deliver to this address?",
      "translation_ko": "배달 주문을 하고 싶은데요, 이 주소로 배송되나요?"
    },
    {
      "text": "我想掛號，請問現在可以看診嗎？",
      "pinyin": "Wǒ xiǎng guàhào, qǐngwèn xiànzài kěyǐ kànzhěn ma?",
      "pinyin_numeric": "wo3 xiang3 gua4hao4, qing3wen4 xian4zai4 ke3yi3 kan4zhen3 ma0",
      "translation_en": "I want to register. Can I see the doctor now?",
      "translation_ko": "접수하고 싶은데요, 지금 진료가 가능한가요?"
    },
    {
      "text": "我想請問你們有賣珍珠奶茶嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen yǒu mài zhēnzhū nǎichá ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men5 you3 mai4 zhen1zhu1 nai3cha2 ma0",
      "translation_en": "I want to ask if you sell bubble milk tea.",
      "translation_ko": "버블 밀크티를 파시나요?"
    },
    {
      "text": "我想打電話給朋友，請問他的電話號碼是多少？",
      "pinyin": "Wǒ xiǎng dǎ diànhuà gěi péngyou, qǐngwèn tā de diànhuà hàomǎ shì duōshao?",
      "pinyin_numeric": "wo3 xiang3 da3 dian4hua4 gei3 peng2you5, qing3wen4 ta1 de0 dian4hua4 hao4ma3 shi4 duo1shao5",
      "translation_en": "I want to call my friend. What is his phone number?",
      "translation_ko": "친구에게 전화를 하고 싶은데요, 그의 전화번호가 어떻게 되나요?"
    },
    {
      "text": "我想請問你們的診所有看牙齒嗎？",
      "pinyin": "Wǒ xiǎng qǐngwèn nǐmen de zhěnsuǒ yǒu kàn yáchǐ ma?",
      "pinyin_numeric": "wo3 xiang3 qing3wen4 ni3men5 de0 zhen3suo3 you3 kan4 ya2chi3 ma0",
      "translation_en": "I want to ask if your clinic provides dental care.",
      "translation_ko": "병원에서 치과 진료를 하나요?"
    }
  ]
}
